{
  "title": "Understanding Gang Culture: A Comprehensive Course",
  "description": "This course aims to provide a thorough understanding of gang culture, its historical context, and its impact on society. It will explore the various aspects of gangs, including their formation, influence, and the socio-economic factors that contribute to their existence.",
  "modules": [
    {
      "id": "module_1",
      "title": "Introduction to Gang Culture",
      "description": "This module will define gang culture, explore its elements, and discuss its significance in contemporary society. Learners will gain insights into the various types of gangs and their motivations."
    },
    {
      "id": "module_2",
      "title": "Historical Context of Gangs",
      "description": "This module will delve into the history of gangs, focusing on their origins and evolution over time. Special attention will be given to the local history of gangs in the learner's area to foster a deeper understanding."
    },
    {
      "id": "module_3",
      "title": "Socio-Economic Factors Influencing Gang Formation",
      "description": "This module will examine the socio-economic conditions that contribute to the formation and persistence of gangs. Topics will include poverty, community disintegration, and the role of law enforcement."
    },
    {
      "id": "module_4",
      "title": "The Impact of Gangs on Society",
      "description": "This module will analyze the broader impact of gang culture on communities, including crime rates, public perception, and the media's portrayal of gangs. Strategies for community engagement and prevention will also be discussed."
    }
  ]
}
